  1→import { tool } from "ai";
  2→import { z } from "zod";
  3→import { RecordId, type Surreal } from "surrealdb";
  4→
  5→/** Known entity tables and the field that holds their display name. */
  6→const ENTITY_NAME_FIELDS: Record<string, string> = {
  7→  project: "name",
  8→  feature: "name",
  9→  person: "name",
 10→  task: "title",
 11→  decision: "summary",
 12→  question: "text",
 13→  observation: "text",
 14→};
 15→
 16→export type EntityRef = {
 17→  entityId: string;
 18→  kind: string;
 19→  name: string;
 20→  status?: string;
 21→};
 22→
 23→/**
 24→ * Walk query result rows and extract unique entity references.
 25→ * A reference is any RecordId whose table is a known entity type.
 26→ * The display name and status are read from sibling fields in the same row.
 27→ */
 28→export function extractEntityRefs(rows: unknown[]): EntityRef[] {
 29→  const seen = new Set<string>();
 30→  const refs: EntityRef[] = [];
 31→
 32→  for (const row of rows) {
 33→    if (row == null || typeof row !== "object") continue;
 34→    const record = row as Record<string, unknown>;
 35→
 36→    for (const value of Object.values(record)) {
 37→      if (!(value instanceof RecordId)) continue;
 38→
 39→      const table = value.table.name;
 40→      if (!(table in ENTITY_NAME_FIELDS)) continue;
 41→
 42→      const key = `${table}:${value.id}`;
 43→      if (seen.has(key)) continue;
 44→      seen.add(key);
 45→
 46→      const nameField = ENTITY_NAME_FIELDS[table];
 47→      const name = typeof record[nameField] === "string"
 48→        ? (record[nameField] as string)
 49→        : key;
 50→
 51→      const ref: EntityRef = { entityId: key, kind: table, name };
 52→      if (typeof record.status === "string") {
 53→        ref.status = record.status as string;
 54→      }
 55→      refs.push(ref);
 56→    }
 57→  }
 58→
 59→  return refs;
 60→}
