 63→  return {
 64→    execute_analytics_query: tool({
 65→      description:
 66→        "Execute a read-only SurrealQL SELECT query against the knowledge graph. Use parameterized queries ($param syntax) for any dynamic values. Always include a LIMIT clause.",
 67→      inputSchema: z.object({
 68→        intent: z.string().min(1).describe("What you are trying to learn from this query"),
 69→        query: z.string().min(1).describe("The SurrealQL SELECT query to execute"),
 70→        parameters: z
 71→          .record(z.string(), z.unknown())
 72→          .optional()
 73→          .describe("Query parameters as key-value pairs, referenced as $key in the query"),
 74→      }),
 75→      execute: async (input) => {
 76→        console.log("[analytics] query:", input.query);
 77→        if (input.parameters) console.log("[analytics] params:", JSON.stringify(input.parameters));
 78→        try {
 79→          const result = await analyticsSurreal.query(input.query, input.parameters ?? {});
 80→          const rows = Array.isArray(result) ? result.flat() : [result];
 81→          const referenced_entities = extractEntityRefs(rows);
 82→          console.log("[analytics] result: %d rows, %d entity refs", rows.length, referenced_entities.length, JSON.stringify(rows).slice(0, 500));
 83→          return {
 84→            success: true as const,
 85→            result: rows,
 86→            row_count: rows.length,
 87→            referenced_entities,
 88→          };
 89→        } catch (error) {
 90→          console.log("[analytics] error:", error instanceof Error ? error.message : String(error));
 91→          return {
 92→            success: false as const,
 93→            error: error instanceof Error ? error.message : String(error),
 94→          };
 95→        }
 96→      },
 97→    }),
 98→  };
 99→}
