  1→/**
  2→ * Tool Resolver — Identity Toolset Resolution
  3→ *
  4→ * Resolves an identity's effective toolset by querying can_use edges in the graph.
  5→ * Uses a per-instance Map-based cache with configurable TTL (not a module-level singleton).
  6→ *
  7→ * Port signature (injectable query):
  8→ *   QueryGrantedTools = (identityId, workspaceId) => Promise<ResolvedTool[]>
  9→ *
 10→ * The query function is injected as a dependency, keeping the resolver pure
 11→ * (aside from the cache, which is an explicit parameter).
 12→ */
 13→import { RecordId, type Surreal } from "surrealdb";
 14→
 15→// ---------------------------------------------------------------------------
 16→// Types
 17→// ---------------------------------------------------------------------------
 18→
 19→export type { ResolvedTool } from "./tool-injector";
 20→
 21→/** Resolved tool from can_use graph query. Re-exported from tool-injector. */
 22→import type { ResolvedTool } from "./tool-injector";
 23→
 24→/** Port: query function for fetching granted tools from the graph. */
 25→export type QueryGrantedTools = (
 26→  identityId: string,
 27→  workspaceId: string,
 28→) => Promise<ResolvedTool[]>;
 29→
 30→/** Cache entry with TTL tracking. */
 31→type CacheEntry = {
 32→  tools: ResolvedTool[];
 33→  populatedAt: number;
 34→};
 35→
 36→/** Per-instance cache (Map-based, injected via deps). */
 37→export type ToolResolutionCache = {
 38→  readonly cache: Map<string, CacheEntry>;
 39→  readonly ttlMs: number;
 40→};
 41→
 42→// ---------------------------------------------------------------------------
 43→// Cache Factory
 44→// ---------------------------------------------------------------------------
 45→
 46→const DEFAULT_TTL_MS = 60_000; // 60 seconds
 47→
 48→/**
 49→ * Create a new tool resolution cache instance.
 50→ * Each call returns a fresh Map — no module-level singletons.
 51→ */
 52→export function createToolResolutionCache(
 53→  ttlMs: number = DEFAULT_TTL_MS,
 54→): ToolResolutionCache {
 55→  return {
 56→    cache: new Map(),
 57→    ttlMs,
 58→  };
 59→}
 60→
 61→// ---------------------------------------------------------------------------
 62→// Resolver (pure core with injectable query)
 63→// ---------------------------------------------------------------------------
 64→
 65→/**
 66→ * Resolve the effective toolset for an identity within a workspace.
 67→ *
 68→ * - Checks cache first (composite key: identityId + workspaceId)
 69→ * - If cache miss or expired, calls the query function and caches the result
 70→ * - Returns ResolvedTool[] (may be empty for identities with no grants)
 71→ */
 72→export async function resolveToolsForIdentity(
 73→  identityId: string,
 74→  workspaceId: string,
 75→  queryGrantedTools: QueryGrantedTools,
 76→  cache: ToolResolutionCache,
 77→): Promise<ResolvedTool[]> {
 78→  const cacheKey = `${identityId}:${workspaceId}`;
 79→  const now = Date.now();
 80→
 81→  const cached = cache.cache.get(cacheKey);
 82→  if (cached && now - cached.populatedAt < cache.ttlMs) {
 83→    return cached.tools;
 84→  }
 85→
 86→  const tools = await queryGrantedTools(identityId, workspaceId);
 87→  cache.cache.set(cacheKey, { tools, populatedAt: now });
 88→
 89→  return tools;
 90→}
 91→
 92→// ---------------------------------------------------------------------------
 93→// Adapter: SurrealDB Query Function Factory
 94→// ---------------------------------------------------------------------------
 95→
 96→/**
 97→ * Create a QueryGrantedTools function backed by SurrealDB.
 98→ * Queries can_use edges to find active tools granted to the identity.
 99→ */
100→export function createQueryGrantedTools(surreal: Surreal): QueryGrantedTools {
101→  return async (identityId: string, workspaceId: string): Promise<ResolvedTool[]> => {
102→    const identityRecord = new RecordId("identity", identityId);
103→    const workspaceRecord = new RecordId("workspace", workspaceId);
104→
105→    type ToolRow = {
106→      name: string;
107→      description: string;
108→      input_schema: Record<string, unknown>;
109→      toolkit: string;
110→      risk_level: string;
111→    };
112→
113→    const results = await surreal.query<[ToolRow[]]>(
114→      `SELECT out.name AS name, out.description AS description, out.input_schema AS input_schema, out.toolkit AS toolkit, out.risk_level AS risk_level
115→       FROM can_use
116→       WHERE in = $identity AND out.status = 'active' AND out.workspace = $workspace;`,
117→      { identity: identityRecord, workspace: workspaceRecord },
118→    );
119→
120→    return (results[0] ?? []).map((row) => ({
121→      name: row.name,
122→      description: row.description,
123→      input_schema: row.input_schema,
124→      toolkit: row.toolkit,
125→      risk_level: row.risk_level,
126→    }));
127→  };
128→}
129→

  1→/**
  2→ * Tool Router -- Pure Function
  3→ *
  4→ * Classifies tool_use blocks from Anthropic responses as brain-native, integration,
  5→ * or unknown based on the resolved toolset from step 7.5.
  6→ *
  7→ * Pure: no side effects, no IO imports. Takes data in, returns classification out.
  8→ *
  9→ * Step 8.5 in the proxy pipeline (between response read and client return).
 10→ */
 11→import type { ResolvedTool } from "./tool-injector";
 12→
 13→// ---------------------------------------------------------------------------
 14→// Types
 15→// ---------------------------------------------------------------------------
 16→
 17→/** Anthropic tool_use content block from a Messages API response. */
 18→export type ToolUseBlock = {
 19→  type: "tool_use";
 20→  id: string;
 21→  name: string;
 22→  input: Record<string, unknown>;
 23→};
 24→
 25→/** Classification result for a single tool_use block. */
 26→export type ClassifiedToolCall =
 27→  | { classification: "brain-native"; toolUse: ToolUseBlock; resolvedTool: ResolvedTool }
 28→  | { classification: "integration"; toolUse: ToolUseBlock; resolvedTool: ResolvedTool }
 29→  | { classification: "unknown"; toolUse: ToolUseBlock };
 30→
 31→/** Classification summary for all tool_use blocks in a response. */
 32→export type ToolRoutingResult = {
 33→  readonly classified: ClassifiedToolCall[];
 34→  readonly hasBrainNative: boolean;
 35→  readonly allUnknown: boolean;
 36→};
 37→
 38→// ---------------------------------------------------------------------------
 39→// Pure Function: classifyToolCalls
 40→// ---------------------------------------------------------------------------
 41→
 42→/**
 43→ * Classify an array of tool_use blocks against the resolved toolset.
 44→ *
 45→ * - toolkit === "brain" -> brain-native (executed locally via graph queries)
 46→ * - toolkit present but not "brain" -> integration (needs credential brokerage)
 47→ * - not found in resolvedTools -> unknown (pass through to runtime)
 48→ */
 49→export function classifyToolCalls(
 50→  toolUseBlocks: ToolUseBlock[],
 51→  resolvedTools: ResolvedTool[],
 52→): ToolRoutingResult {
 53→  const toolsByName = new Map(resolvedTools.map((tool) => [tool.name, tool]));
 54→
 55→  const classified: ClassifiedToolCall[] = toolUseBlocks.map((toolUse) => {
 56→    const resolved = toolsByName.get(toolUse.name);
 57→
 58→    if (!resolved) {
 59→      return { classification: "unknown" as const, toolUse };
 60→    }
 61→
 62→    if (resolved.toolkit === "brain") {
 63→      return { classification: "brain-native" as const, toolUse, resolvedTool: resolved };
 64→    }
 65→
 66→    return { classification: "integration" as const, toolUse, resolvedTool: resolved };
 67→  });
 68→
 69→  const hasBrainNative = classified.some((c) => c.classification === "brain-native");
 70→  const allUnknown = classified.every((c) => c.classification === "unknown");
 71→
 72→  return { classified, hasBrainNative, allUnknown };
 73→}
 74→
 75→// ---------------------------------------------------------------------------
 76→// Pure Helper: extractToolUseBlocks
 77→// ---------------------------------------------------------------------------
 78→
 79→/** Extract tool_use content blocks from an Anthropic Messages API response body. */
 80→export function extractToolUseBlocks(
 81→  responseBody: Record<string, unknown>,
 82→): ToolUseBlock[] {
 83→  const content = responseBody.content as Array<Record<string, unknown>> | undefined;
 84→  if (!Array.isArray(content)) return [];
 85→
 86→  return content.filter(
 87→    (block): block is ToolUseBlock =>
 88→      block.type === "tool_use" &&
 89→      typeof block.id === "string" &&
 90→      typeof block.name === "string" &&
 91→      typeof block.input === "object" &&
 92→      block.input !== null,
 93→  );
 94→}
 95→
 96→/** Check if an Anthropic response indicates tool use (stop_reason === "tool_use"). */
 97→export function isToolUseResponse(responseBody: Record<string, unknown>): boolean {
 98→  return responseBody.stop_reason === "tool_use";
 99→}
