  1→/**
  2→ * HTTP routes for credential provider CRUD and account connection.
  3→ *
  4→ * POST /api/workspaces/:workspaceId/providers -- create provider
  5→ * GET  /api/workspaces/:workspaceId/providers -- list providers
  6→ * POST /api/workspaces/:workspaceId/accounts/connect/:providerId -- connect account
  7→ * GET  /api/workspaces/:workspaceId/accounts -- list connected accounts
  8→ *
  9→ * Secrets encrypted before storage, never returned as plaintext.
 10→ */
 11→import { RecordId } from "surrealdb";
 12→import { HttpError } from "../http/errors";
 13→import { jsonError, jsonResponse } from "../http/response";
 14→import type { ServerDependencies } from "../runtime/types";
 15→import { resolveWorkspaceRecord } from "../workspace/workspace-scope";
 16→import {
 17→  providerNameExists,
 18→  createProvider,
 19→  listProviders,
 20→  getProviderById,
 21→  activeAccountExists,
 22→  createConnectedAccount,
 23→  listConnectedAccounts,
 24→} from "./queries";
 25→import { encryptSecret } from "./encryption";
 26→import { buildAuthorizationUrl, storeOAuthState } from "./oauth-flow";
 27→import type {
 28→  CreateProviderInput,
 29→  CredentialProviderRecord,
 30→  ProviderApiResponse,
 31→  ConnectedAccountRecord,
 32→  ConnectedAccountApiResponse,
 33→  ConnectAccountInput,
 34→} from "./types";
 35→import { log } from "../telemetry/logger";
 36→
 37→const VALID_AUTH_METHODS = ["oauth2", "api_key", "bearer", "basic"] as const;
 38→
 39→// ---------------------------------------------------------------------------
 40→// Response mapping -- strip encrypted fields, expose has_client_secret flag
 41→// ---------------------------------------------------------------------------
 42→
 43→function toApiResponse(record: CredentialProviderRecord): ProviderApiResponse {
 44→  const response: ProviderApiResponse = {
 45→    id: record.id.id as string,
 46→    name: record.name,
 47→    display_name: record.display_name,
 48→    auth_method: record.auth_method,
 49→    has_client_secret: !!record.client_secret_encrypted,
 50→    created_at: record.created_at instanceof Date
 51→      ? record.created_at.toISOString()
 52→      : String(record.created_at),
 53→  };
 54→
 55→  if (record.authorization_url) response.authorization_url = record.authorization_url;
 56→  if (record.token_url) response.token_url = record.token_url;
 57→  if (record.client_id) response.client_id = record.client_id;
 58→  if (record.scopes) response.scopes = record.scopes;
 59→  if (record.api_key_header) response.api_key_header = record.api_key_header;
 60→
 61→  return response;
 62→}
 63→
 64→// ---------------------------------------------------------------------------
 65→// Route handlers
 66→// ---------------------------------------------------------------------------
 67→
 68→export function createProviderRouteHandlers(deps: ServerDependencies) {
 69→  const encryptionKey = deps.config.toolEncryptionKey;
 70→
 71→  async function handleCreate(workspaceId: string, request: Request): Promise<Response> {
 72→    let workspaceRecord;
 73→    try {
 74→      workspaceRecord = await resolveWorkspaceRecord(deps.surreal, workspaceId);
 75→    } catch (error) {
 76→      if (error instanceof HttpError) {
 77→        return jsonError(error.message, error.status);
 78→      }
 79→      log.error("provider.create", "Failed to resolve workspace", error, { workspaceId });
 80→      return jsonError("internal error", 500);
 81→    }
 82→
 83→    let body: CreateProviderInput;
 84→    try {
 85→      body = await request.json() as CreateProviderInput;
 86→    } catch {
 87→      return jsonError("invalid JSON body", 400);
 88→    }
 89→
 90→    // Validate required fields
 91→    if (!body.name || typeof body.name !== "string") {
 92→      return jsonError("name is required", 400);
 93→    }
 94→    if (!body.display_name || typeof body.display_name !== "string") {
 95→      return jsonError("display_name is required", 400);
 96→    }
 97→    if (!body.auth_method || !VALID_AUTH_METHODS.includes(body.auth_method as any)) {
 98→      return jsonError(`auth_method must be one of: ${VALID_AUTH_METHODS.join(", ")}`, 400);
 99→    }
100→
101→    // Check duplicate name within workspace
102→    const exists = await providerNameExists(deps.surreal, workspaceRecord, body.name);
103→    if (exists) {
104→      return jsonError(`provider with name "${body.name}" already exists in workspace`, 409);
105→    }
106→
107→    // Build content, encrypting secret if present
108→    const content: Record<string, unknown> = {
109→      name: body.name,
110→      display_name: body.display_name,
111→      auth_method: body.auth_method,
112→    };
113→
114→    if (body.authorization_url) content.authorization_url = body.authorization_url;
115→    if (body.token_url) content.token_url = body.token_url;
116→    if (body.client_id) content.client_id = body.client_id;
117→    if (body.scopes) content.scopes = body.scopes;
118→    if (body.api_key_header) content.api_key_header = body.api_key_header;
119→
120→    if (body.client_secret && encryptionKey) {
121→      content.client_secret_encrypted = encryptSecret(body.client_secret, encryptionKey);
122→    }
123→
124→    const record = await createProvider(deps.surreal, workspaceRecord, content);
125→    return jsonResponse(toApiResponse(record), 201);
126→  }
127→
128→  async function handleList(workspaceId: string, _request: Request): Promise<Response> {
129→    let workspaceRecord;
130→    try {
131→      workspaceRecord = await resolveWorkspaceRecord(deps.surreal, workspaceId);
132→    } catch (error) {
133→      if (error instanceof HttpError) {
134→        return jsonError(error.message, error.status);
135→      }
136→      log.error("provider.list", "Failed to resolve workspace", error, { workspaceId });
137→      return jsonError("internal error", 500);
138→    }
139→
140→    const records = await listProviders(deps.surreal, workspaceRecord);
141→    const providers = records.map(toApiResponse);
142→    return jsonResponse({ providers }, 200);
143→  }
144→
145→  return { handleCreate, handleList };
146→}
147→
148→// ---------------------------------------------------------------------------
149→// Account response mapping -- strip encrypted fields
150→// ---------------------------------------------------------------------------
151→
152→function toAccountApiResponse(record: ConnectedAccountRecord): ConnectedAccountApiResponse {
153→  return {
154→    id: record.id.id as string,
155→    provider_id: record.provider.id as string,
156→    status: record.status,
157→    has_api_key: !!record.api_key_encrypted,
158→    has_bearer_token: !!record.bearer_token_encrypted,
159→    has_basic_credentials: !!record.basic_password_encrypted,
160→    has_access_token: !!record.access_token_encrypted,
161→    connected_at: record.connected_at instanceof Date
162→      ? record.connected_at.toISOString()
163→      : String(record.connected_at),
164→  };
165→}
166→
167→// ---------------------------------------------------------------------------
168→// Account connection route handlers
169→// ---------------------------------------------------------------------------
170→
171→export function createAccountRouteHandlers(deps: ServerDependencies) {
172→  const encryptionKey = deps.config.toolEncryptionKey;
173→
174→  /**
175→   * POST /api/workspaces/:workspaceId/accounts/connect/:providerId
176→   *
177→   * For api_key/bearer/basic: encrypts credentials and creates connected_account.
178→   * For oauth2: returns redirect URL for user to authorize at provider.
179→   */
180→  async function handleConnect(
181→    workspaceId: string,
182→    providerId: string,
183→    request: Request,
184→  ): Promise<Response> {
185→    let workspaceRecord;
186→    try {
187→      workspaceRecord = await resolveWorkspaceRecord(deps.surreal, workspaceId);
188→    } catch (error) {
189→      if (error instanceof HttpError) {
190→        return jsonError(error.message, error.status);
191→      }
192→      log.error("account.connect", "Failed to resolve workspace", error, { workspaceId });
193→      return jsonError("internal error", 500);
194→    }
195→
196→    // Look up the credential provider
197→    const provider = await getProviderById(deps.surreal, providerId);
198→    if (!provider) {
199→      return jsonError("credential provider not found", 404);
200→    }
201→
202→    // Extract identity from request headers (set by DPoP middleware)
203→    const identityId = request.headers.get("X-Brain-Identity");
204→    if (!identityId) {
205→      return jsonError("identity required", 401);
206→    }
207→
208→    const identityRecord = new RecordId("identity", identityId);
209→    const providerRecord = new RecordId("credential_provider", providerId);
210→
211→    // Check for existing active account
212→    const alreadyExists = await activeAccountExists(deps.surreal, identityRecord, providerRecord);
213→    if (alreadyExists) {
214→      return jsonError("active account already exists for this provider", 409);
215→    }
216→
217→    // OAuth2: return redirect URL
218→    if (provider.auth_method === "oauth2") {
219→      const state = crypto.randomUUID();
220→      const baseUrl = request.headers.get("Origin") ?? `${new URL(request.url).origin}`;
221→      const redirectUri = `${baseUrl}/api/workspaces/${workspaceId}/accounts/oauth2/callback`;
222→
223→      storeOAuthState(state, {
224→        providerId,
225→        identityId,
226→        workspaceId,
227→        createdAt: Date.now(),
228→      });
229→
230→      const redirectUrl = buildAuthorizationUrl(provider, redirectUri, state);
231→      return jsonResponse({ redirect_url: redirectUrl, state }, 200);
232→    }
233→
234→    // Static credentials: parse body and encrypt
235→    let body: ConnectAccountInput;
236→    try {
237→      body = await request.json() as ConnectAccountInput;
238→    } catch {
239→      return jsonError("invalid JSON body", 400);
240→    }
241→
242→    if (!encryptionKey) {
243→      log.error("account.connect", "TOOL_ENCRYPTION_KEY not configured", undefined, { workspaceId });
244→      return jsonError("encryption not configured", 500);
245→    }
246→
247→    const content: Record<string, unknown> = {
248→      identity: identityRecord,
249→      provider: providerRecord,
250→      workspace: workspaceRecord,
251→      status: "active",
252→    };
253→
254→    switch (provider.auth_method) {
255→      case "api_key": {
256→        if (!body.api_key) {
257→          return jsonError("api_key is required for api_key auth method", 400);
258→        }
259→        content.api_key_encrypted = encryptSecret(body.api_key, encryptionKey);
260→        break;
261→      }
262→      case "bearer": {
263→        if (!body.bearer_token) {
264→          return jsonError("bearer_token is required for bearer auth method", 400);
265→        }
266→        content.bearer_token_encrypted = encryptSecret(body.bearer_token, encryptionKey);
267→        break;
268→      }
269→      case "basic": {
270→        if (!body.basic_username || !body.basic_password) {
271→          return jsonError("basic_username and basic_password are required for basic auth method", 400);
272→        }
273→        content.basic_username = body.basic_username;
274→        content.basic_password_encrypted = encryptSecret(body.basic_password, encryptionKey);
275→        break;
276→      }
277→      default:
278→        return jsonError(`unsupported auth method: ${provider.auth_method}`, 400);
279→    }
280→
281→    const record = await createConnectedAccount(deps.surreal, content);
282→    return jsonResponse(toAccountApiResponse(record), 201);
283→  }
284→
285→  /**
286→   * GET /api/workspaces/:workspaceId/accounts
287→   *
288→   * List connected accounts for the authenticated identity.
289→   */
290→  async function handleListAccounts(
291→    workspaceId: string,
292→    request: Request,
293→  ): Promise<Response> {
294→    let workspaceRecord;
295→    try {
296→      workspaceRecord = await resolveWorkspaceRecord(deps.surreal, workspaceId);
297→    } catch (error) {
298→      if (error instanceof HttpError) {
299→        return jsonError(error.message, error.status);
300→      }
301→      log.error("account.list", "Failed to resolve workspace", error, { workspaceId });
302→      return jsonError("internal error", 500);
303→    }
304→
305→    const identityId = request.headers.get("X-Brain-Identity");
306→    if (!identityId) {
307→      return jsonError("identity required", 401);
308→    }
309→
310→    const identityRecord = new RecordId("identity", identityId);
311→    const records = await listConnectedAccounts(deps.surreal, identityRecord, workspaceRecord);
312→    const accounts = records.map(toAccountApiResponse);
313→    return jsonResponse({ accounts }, 200);
314→  }
315→
316→  return { handleConnect, handleListAccounts };
317→}
318→

 1→/**
 2→ * Tool Injector — Pure Function
 3→ *
 4→ * Merges Brain-managed tool definitions into the LLM request body's tools[].
 5→ * Runtime tools are preserved unmodified; Brain tools are appended after.
 6→ * When a name collision occurs, the runtime version takes precedence (Brain tool skipped).
 7→ *
 8→ * Step 7.5 in the proxy pipeline (between context injection and forwarding).
 9→ */
10→
11→// ---------------------------------------------------------------------------
12→// Types
13→// ---------------------------------------------------------------------------
14→
15→/** Anthropic tool format (the shape expected by the Messages API). */
16→export type AnthropicTool = {
17→  name: string;
18→  description: string;
19→  input_schema: Record<string, unknown>;
20→};
21→
22→/** Resolved tool from Brain's can_use graph query (internal, richer than Anthropic format). */
23→export type ResolvedTool = {
24→  name: string;
25→  description: string;
26→  input_schema: Record<string, unknown>;
27→  toolkit: string;
28→  risk_level: string;
29→};
30→
31→// ---------------------------------------------------------------------------
32→// Pure Function: injectTools
33→// ---------------------------------------------------------------------------
34→
35→/**
36→ * Merge Brain-managed tools into the request's tool list.
37→ *
38→ * - Runtime tools are preserved first, unmodified.
39→ * - Brain tools are appended, but only if no runtime tool shares the same name.
40→ * - Output is in Anthropic tool format (name, description, input_schema only).
41→ *
42→ * @param runtimeTools - Tools already in the request body (may be undefined)
43→ * @param resolvedTools - Brain-managed tools resolved from can_use edges
44→ * @returns Merged tool list in Anthropic format
45→ */
46→export function injectTools(
47→  runtimeTools: AnthropicTool[] | undefined,
48→  resolvedTools: ResolvedTool[],
49→): AnthropicTool[] {
50→  const existing = runtimeTools ?? [];
51→
52→  if (resolvedTools.length === 0) {
53→    return [...existing];
54→  }
55→
56→  const runtimeNames = new Set(existing.map((tool) => tool.name));
57→
58→  const brainToolsToInject: AnthropicTool[] = resolvedTools
59→    .filter((tool) => !runtimeNames.has(tool.name))
60→    .map(toAnthropicFormat);
61→
62→  return [...existing, ...brainToolsToInject];
63→}
64→
65→// ---------------------------------------------------------------------------
66→// Internal: Format Conversion
67→// ---------------------------------------------------------------------------
68→
69→/** Strip internal fields (toolkit, risk_level) to produce Anthropic-compatible tool. */
70→function toAnthropicFormat(tool: ResolvedTool): AnthropicTool {
71→  return {
72→    name: tool.name,
73→    description: tool.description,
74→    input_schema: tool.input_schema,
75→  };
76→}
77→

  1→/**
  2→ * Tool Executor -- Effect Boundary
  3→ *
  4→ * Executes Brain-native tool calls via graph queries. This is the adapter/effect
  5→ * boundary -- it performs IO (SurrealDB queries) to fulfill tool calls that the
  6→ * pure tool-router classified as "brain-native".
  7→ *
  8→ * Each Brain-native tool handler is a function: (input, deps) -> ToolExecutionResult.
  9→ * Unknown tool names produce an error result (not an exception).
 10→ *
 11→ * Step 8.5 in the proxy pipeline.
 12→ */
 13→import { RecordId, type Surreal } from "surrealdb";
 14→import type { ClassifiedToolCall } from "./tool-router";
 15→import { log } from "../telemetry/logger";
 16→import { captureToolTrace } from "./tool-trace-writer";
 17→
 18→// ---------------------------------------------------------------------------
 19→// Types
 20→// ---------------------------------------------------------------------------
 21→
 22→/** Result of executing a single Brain-native tool call. */
 23→export type ToolExecutionResult = {
 24→  readonly toolUseId: string;
 25→  readonly content: string;
 26→  readonly isError: boolean;
 27→};
 28→
 29→/** Dependencies injected into tool executors. */
 30→export type ToolExecutorDeps = {
 31→  readonly surreal: Surreal;
 32→  readonly workspaceId: string;
 33→  readonly identityId?: string;
 34→};
 35→
 36→/** Anthropic tool_result content block for follow-up requests. */
 37→export type ToolResultMessage = {
 38→  role: "user";
 39→  content: Array<{
 40→    type: "tool_result";
 41→    tool_use_id: string;
 42→    content: string;
 43→    is_error?: boolean;
 44→  }>;
 45→};
 46→
 47→/** Handler for a single Brain-native tool. */
 48→type BrainToolHandler = (
 49→  input: Record<string, unknown>,
 50→  deps: ToolExecutorDeps,
 51→) => Promise<ToolExecutionResult>;
 52→
 53→// ---------------------------------------------------------------------------
 54→// Brain-Native Tool Handlers
 55→// ---------------------------------------------------------------------------
 56→
 57→const searchEntitiesHandler: BrainToolHandler = async (input, deps) => {
 58→  const query = typeof input.query === "string" ? input.query : "";
 59→
 60→  if (!query.trim()) {
 61→    return {
 62→      toolUseId: "", // filled by caller
 63→      content: JSON.stringify({ results: [], message: "Empty search query" }),
 64→      isError: false,
 65→    };
 66→  }
 67→
 68→  const workspaceRecord = new RecordId("workspace", deps.workspaceId);
 69→
 70→  // Simple keyword search across tasks, decisions, and features
 71→  // Uses basic string matching (CONTAINS) for the walking skeleton.
 72→  // Future: BM25 fulltext search.
 73→  type EntityRow = {
 74→    id: RecordId;
 75→    table: string;
 76→    title?: string;
 77→    summary?: string;
 78→    text?: string;
 79→    status?: string;
 80→  };
 81→
 82→  const results = await deps.surreal.query<[EntityRow[], EntityRow[], EntityRow[]]>(
 83→    `SELECT id, 'task' AS table, title, status FROM task WHERE workspace = $ws AND (title CONTAINS $q) LIMIT 10;
 84→     SELECT id, 'decision' AS table, summary, status FROM decision WHERE workspace = $ws AND (summary CONTAINS $q) LIMIT 10;
 85→     SELECT id, 'feature' AS table, title, status FROM feature WHERE workspace = $ws AND (title CONTAINS $q) LIMIT 10;`,
 86→    { ws: workspaceRecord, q: query },
 87→  );
 88→
 89→  const entities = [
 90→    ...(results[0] ?? []).map((row) => ({
 91→      id: (row.id as RecordId).id as string,
 92→      type: "task",
 93→      title: row.title ?? "",
 94→      status: row.status ?? "",
 95→    })),
 96→    ...(results[1] ?? []).map((row) => ({
 97→      id: (row.id as RecordId).id as string,
 98→      type: "decision",
 99→      title: row.summary ?? "",
100→      status: row.status ?? "",
101→    })),
102→    ...(results[2] ?? []).map((row) => ({
103→      id: (row.id as RecordId).id as string,
104→      type: "feature",
105→      title: row.title ?? "",
106→      status: row.status ?? "",
107→    })),
108→  ];
109→
110→  return {
111→    toolUseId: "", // filled by caller
112→    content: JSON.stringify({ results: entities, count: entities.length }),
113→    isError: false,
114→  };
115→};
116→
117→/** Registry of Brain-native tool handlers, keyed by tool name. */
118→const brainToolHandlers: ReadonlyMap<string, BrainToolHandler> = new Map([
119→  ["search_entities", searchEntitiesHandler],
120→]);
121→
122→// ---------------------------------------------------------------------------
123→// Effect Boundary: executeBrainNativeTools
124→// ---------------------------------------------------------------------------
125→
126→/**
127→ * Execute all brain-native tool calls and return tool_result messages.
128→ *
129→ * - Each classified brain-native call is dispatched to its handler.
130→ * - Unknown handlers produce an error result (graceful, not HTTP 500).
131→ * - All errors are caught and returned as is_error tool_results.
132→ */
133→export async function executeBrainNativeTools(
134→  classifiedCalls: ClassifiedToolCall[],
135→  deps: ToolExecutorDeps,
136→): Promise<ToolExecutionResult[]> {
137→  const brainNativeCalls = classifiedCalls.filter(
138→    (c): c is Extract<ClassifiedToolCall, { classification: "brain-native" }> =>
139→      c.classification === "brain-native",
140→  );
141→
142→  const results: ToolExecutionResult[] = [];
143→
144→  for (const call of brainNativeCalls) {
145→    const handler = brainToolHandlers.get(call.toolUse.name);
146→
147→    if (!handler) {
148→      results.push({
149→        toolUseId: call.toolUse.id,
150→        content: JSON.stringify({
151→          error: `No handler registered for brain-native tool: ${call.toolUse.name}`,
152→        }),
153→        isError: true,
154→      });
155→      continue;
156→    }
157→
158→    const startMs = performance.now();
159→    try {
160→      const result = await handler(call.toolUse.input, deps);
161→      const durationMs = performance.now() - startMs;
162→      results.push({
163→        ...result,
164→        toolUseId: call.toolUse.id,
165→      });
166→
167→      // Fire-and-forget trace capture (do not block tool result delivery)
168→      captureToolTrace(
169→        {
170→          toolName: call.toolUse.name,
171→          workspaceId: deps.workspaceId,
172→          identityId: deps.identityId,
173→          outcome: "success",
174→          durationMs,
175→          input: call.toolUse.input as Record<string, unknown>,
176→          output: { content: result.content },
177→        },
178→        { surreal: deps.surreal },
179→      ).catch((traceError) => {
180→        log.warn("proxy.tool_executor.trace_failed", "Tool trace capture failed", {
181→          tool_name: call.toolUse.name,
182→          error: String(traceError),
183→        });
184→      });
185→    } catch (error) {
186→      const durationMs = performance.now() - startMs;
187→      log.warn("proxy.tool_executor.handler_error", "Brain-native tool execution failed", {
188→        tool_name: call.toolUse.name,
189→        tool_use_id: call.toolUse.id,
190→        error: String(error),
191→      });
192→      results.push({
193→        toolUseId: call.toolUse.id,
194→        content: JSON.stringify({
195→          error: `Tool execution failed: ${String(error)}`,
196→        }),
197→        isError: true,
198→      });
199→
200→      // Trace error outcome too
201→      captureToolTrace(
202→        {
203→          toolName: call.toolUse.name,
204→          workspaceId: deps.workspaceId,
205→          identityId: deps.identityId,
206→          outcome: "error",
207→          durationMs,
208→        },
209→        { surreal: deps.surreal },
210→      ).catch((traceError) => {
211→        log.warn("proxy.tool_executor.trace_failed", "Tool trace capture failed", {
212→          tool_name: call.toolUse.name,
213→          error: String(traceError),
214→        });
215→      });
216→    }
217→  }
218→
219→  return results;
220→}
221→
222→// ---------------------------------------------------------------------------
223→// Helper: buildToolResultMessages
224→// ---------------------------------------------------------------------------
225→
226→/**
227→ * Build an Anthropic tool_result message from execution results.
228→ * Used to construct the follow-up request in the tool use loop.
229→ */
230→export function buildToolResultMessage(
231→  results: ToolExecutionResult[],
232→): ToolResultMessage {
233→  return {
234→    role: "user",
235→    content: results.map((result) => ({
236→      type: "tool_result" as const,
237→      tool_use_id: result.toolUseId,
238→      content: result.content,
239→      ...(result.isError ? { is_error: true } : {}),
240→    })),
241→  };
242→}
