 1→import type { ToolExecutionOptions } from "ai";
 2→import { RecordId } from "surrealdb";
 3→import type { ChatToolExecutionContext } from "./types";
 4→
 5→export function requireToolContext(options: ToolExecutionOptions): ChatToolExecutionContext {
 6→  const context = options.experimental_context as ChatToolExecutionContext | undefined;
 7→  if (!context) {
 8→    throw new Error("chat tool execution context is missing");
 9→  }
10→
11→  if (!context.workspaceRecord || !context.currentMessageRecord || !context.conversationRecord) {
12→    throw new Error("chat tool execution context is malformed");
13→  }
14→
15→  return context;
16→}
17→
18→export function toDecisionRecordId(value: string): RecordId<"decision", string> {
19→  const normalized = value.trim();
20→  if (normalized.length === 0) {
21→    throw new Error("decision id is required");
22→  }
23→
24→  if (normalized.includes(":")) {
25→    const [table, id] = normalized.split(":", 2);
26→    if (table !== "decision" || !id) {
27→      throw new Error("decision id must reference a decision record");
28→    }
29→    return new RecordId("decision", id);
30→  }
31→
32→  return new RecordId("decision", normalized);
33→}
